/**
 * Tests for stop-uncommitted-check.mjs — standalone command hook
 *
 * Spawns the script as a subprocess with controlled git states and asserts
 * on the JSON stdout output (systemMessage text, continue, suppressOutput).
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { execFileSync, execSync } from 'node:child_process';
import { mkdtempSync, writeFileSync, rmSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';

const SCRIPT_PATH = join(__dirname, '..', '..', '..', 'bin', 'stop-uncommitted-check.mjs');

/** Run the hook script, piping empty JSON as stdin (hook protocol). */
function runHook(projectDir: string): { continue: boolean; suppressOutput?: boolean; systemMessage?: string } {
  const result = execFileSync('node', [SCRIPT_PATH], {
    cwd: projectDir,
    encoding: 'utf-8',
    env: { ...process.env, CLAUDE_PROJECT_DIR: projectDir },
    input: JSON.stringify({}),
    timeout: 5000,
  });
  return JSON.parse(result.trim());
}

describe('stop-uncommitted-check.mjs output', () => {
  let tmpDir: string;

  /** Run git in the temp repo with signing disabled. */
  function git(cmd: string) {
    execSync(`git -c commit.gpgsign=false ${cmd}`, { cwd: tmpDir, stdio: 'pipe' });
  }

  beforeEach(() => {
    tmpDir = mkdtempSync(join(tmpdir(), 'stop-uncommitted-'));
    execSync('git init', { cwd: tmpDir, stdio: 'pipe' });
    git('config user.name "Test"');
    git('config user.email "test@test.com"');
    git('commit --allow-empty -m "init"');
  });

  afterEach(() => {
    rmSync(tmpDir, { recursive: true, force: true });
  });

  it('returns silent success for clean repo', () => {
    const output = runHook(tmpDir);
    expect(output).toEqual({ continue: true, suppressOutput: true });
  });

  it('reports staged files in systemMessage', () => {
    writeFileSync(join(tmpDir, 'new.txt'), 'content');
    git('add new.txt');

    const output = runHook(tmpDir);
    expect(output.continue).toBe(true);
    expect(output.suppressOutput).toBeUndefined();
    expect(output.systemMessage).toContain('1 staged');
    expect(output.systemMessage).toContain('uncommitted');
    expect(output.systemMessage).toContain('do not act on these');
  });

  it('reports modified (unstaged) files', () => {
    // Create a committed file, then modify it
    writeFileSync(join(tmpDir, 'file.txt'), 'v1');
    git('add file.txt');
    git('commit -m "add file"');
    writeFileSync(join(tmpDir, 'file.txt'), 'v2');

    const output = runHook(tmpDir);
    expect(output.systemMessage).toContain('1 modified');
    expect(output.systemMessage).toContain('uncommitted');
  });

  it('reports untracked files', () => {
    writeFileSync(join(tmpDir, 'untracked.txt'), 'hello');

    const output = runHook(tmpDir);
    expect(output.systemMessage).toContain('1 untracked');
    expect(output.systemMessage).toContain('uncommitted');
  });

  it('reports mixed states (staged + modified + untracked)', () => {
    // Committed then modified file
    writeFileSync(join(tmpDir, 'tracked.txt'), 'v1');
    git('add tracked.txt');
    git('commit -m "add tracked"');
    writeFileSync(join(tmpDir, 'tracked.txt'), 'v2');

    // Staged file (added AFTER commit so it stays staged)
    writeFileSync(join(tmpDir, 'staged.txt'), 'staged');
    git('add staged.txt');

    // Untracked file
    writeFileSync(join(tmpDir, 'new.txt'), 'new');

    const output = runHook(tmpDir);
    expect(output.systemMessage).toMatch(/1 staged/);
    expect(output.systemMessage).toMatch(/1 modified/);
    expect(output.systemMessage).toMatch(/1 untracked/);
    expect(output.systemMessage).toContain('do not act on these');
  });

  it('includes ork@ version prefix in systemMessage', () => {
    writeFileSync(join(tmpDir, 'file.txt'), 'content');

    const output = runHook(tmpDir);
    // Source has __PLUGIN_VERSION__ placeholder; built version has real version
    expect(output.systemMessage).toMatch(/\[ork@/);
  });

  it('always sets continue: true even with changes', () => {
    writeFileSync(join(tmpDir, 'file.txt'), 'content');
    git('add file.txt');

    const output = runHook(tmpDir);
    expect(output.continue).toBe(true);
  });

  it('returns silent success for non-git directory', () => {
    const nonGitDir = mkdtempSync(join(tmpdir(), 'no-git-'));
    try {
      const output = runHook(nonGitDir);
      expect(output).toEqual({ continue: true, suppressOutput: true });
    } finally {
      rmSync(nonGitDir, { recursive: true, force: true });
    }
  });

  it('does not include "DO NOT investigate" (old verbose message)', () => {
    writeFileSync(join(tmpDir, 'file.txt'), 'content');

    const output = runHook(tmpDir);
    expect(output.systemMessage).not.toContain('DO NOT investigate');
    expect(output.systemMessage).not.toContain('Just acknowledge');
    expect(output.systemMessage).not.toContain('chose to stop');
  });

  it('reports renamed files as staged (R status)', () => {
    writeFileSync(join(tmpDir, 'old.txt'), 'content');
    git('add old.txt');
    git('commit -m "add old"');
    git('mv old.txt new.txt');

    const output = runHook(tmpDir);
    expect(output.systemMessage).toContain('1 staged');
    expect(output.systemMessage).toContain('uncommitted');
  });

  it('reports double-status files (staged then modified again)', () => {
    // MM = staged change + further unstaged modification
    writeFileSync(join(tmpDir, 'file.txt'), 'v1');
    git('add file.txt');
    git('commit -m "add file"');
    writeFileSync(join(tmpDir, 'file.txt'), 'v2');
    git('add file.txt');
    writeFileSync(join(tmpDir, 'file.txt'), 'v3');

    const output = runHook(tmpDir);
    // MM counts as both staged AND modified — correct UX
    expect(output.systemMessage).toContain('1 staged');
    expect(output.systemMessage).toContain('1 modified');
    expect(output.systemMessage).toContain('uncommitted');
  });

  it('systemMessage is concise (under 100 chars)', () => {
    // Even with all three categories, message should be short
    writeFileSync(join(tmpDir, 'staged.txt'), 'staged');
    git('add staged.txt');
    writeFileSync(join(tmpDir, 'untracked.txt'), 'new');

    const output = runHook(tmpDir);
    expect(output.systemMessage!.length).toBeLessThan(100);
  });
});
